import React, { useState } from "react";
import FloatingInput from "./FloatingInput";

export default function UserRegister({ closeModal }) {
  const [formData, setFormData] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const [errors, setErrors] = useState({});
  const BASE_URL = "http://localhost:8086";

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const validate = () => {
    const err = {};

    if (!formData.username) err.username = "Required";
    if (!formData.name) err.name = "Required";

    // 🔥 STRICT EMAIL VALIDATION
    if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(formData.email)) {
      err.email = "Use ITXXXXXXXX@my.sliit.lk format";
    }

    if (formData.password.length < 6) {
      err.password = "Min 6 chars";
    }

    if (formData.password !== formData.confirmPassword) {
      err.confirmPassword = "Passwords mismatch";
    }

    return err;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const err = validate();
    if (Object.keys(err).length > 0) {
      setErrors(err);
      return;
    }

    await fetch(`${BASE_URL}/user`, {
      method: "POST",
      headers: {"Content-Type": "application/json"},
      body: JSON.stringify(formData),
    });

    alert("Registered successfully");
    closeModal();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <FloatingInput name="username" label="Username" onChange={handleChange}/>
      <FloatingInput name="name" label="Name" onChange={handleChange}/>
      <FloatingInput name="email" label="SLIIT Email" onChange={handleChange}/>
      {errors.email && <p>{errors.email}</p>}

      <FloatingInput name="password" type="password" label="Password" onChange={handleChange}/>
      <FloatingInput name="confirmPassword" type="password" label="Confirm Password" onChange={handleChange}/>
      {errors.confirmPassword && <p>{errors.confirmPassword}</p>}

      <button type="submit">Register</button>
    </form>
  );
}
